onClick:
{{(() => {
     if (!ItemNameInput.text ) {
       showAlert("Please enter item name", "error");
       return;
     }

     const currentItems = appsmith.store.newOrderItems || [];
     const newItem = {
       name: ItemNameInput.text,
       ski: parseFloat(ItemSkuInput.text),
       quantity: parseInt(ItemQuantityInput.text) || 1
     };

     storeValue('newOrderItems', [...currentItems, newItem]);

     // Clear inputs
     ItemNameInput.setValue('');
     ItemSkuInput.setValue('');
     ItemQuantityInput.setValue('1');

     showAlert("Item added!", "success");
   })()}}
